// Normalise the queue payload (Airtable/Sheet/CMS all differ) and pick the
// highest-priority pending item. Lower priority number = more urgent.
const body = $input.first().json || {};
let rows = body.records || body.items || body.data || body.rows || [];
if (!Array.isArray(rows)) rows = [];

const pending = rows
  .map((r) => {
    const f = r.fields || r;
    return {
      queue_id: r.id || f.id || f.queue_id,
      target_keyword: (f.target_keyword || f.keyword || '').trim(),
      priority: Number(f.priority ?? 999),
      status: (f.status || 'pending').toLowerCase(),
      notes: f.notes || ''
    };
  })
  .filter((r) => r.status === 'pending' && r.target_keyword);

pending.sort((a, b) => a.priority - b.priority);

if (pending.length === 0) {
  return [{ json: { has_topic: false } }];
}

const chosen = pending[0];
return [
  {
    json: {
      has_topic: true,
      queue_id: chosen.queue_id,
      target_keyword: chosen.target_keyword,
      priority: chosen.priority,
      notes: chosen.notes,
      outline_attempt: 0,
      run_started_at: new Date().toISOString()
    }
  }
];

// Build a research brief from the SERP payload. Handle an empty / errored
// SERP gracefully so the pipeline still produces a sensible outline.
const topic = $('Pick Next Topic').first().json;
const serp = $input.first().json || {};

const organic = serp.organic_results || [];
const paa = serp.related_questions || serp.people_also_ask || [];

// Pull competitor headings where the SERP API exposes them.
const competitorHeadings = [];
for (const r of organic.slice(0, 10)) {
  if (Array.isArray(r.headings)) competitorHeadings.push(...r.headings);
  if (r.title) competitorHeadings.push(r.title);
}

const paaQuestions = paa
  .map((q) => (typeof q === 'string' ? q : q.question))
  .filter(Boolean)
  .slice(0, 8);

// Crude subtopic frequency from titles/snippets.
const text = organic
  .map((r) => `${r.title || ''} ${r.snippet || ''}`)
  .join(' ')
  .toLowerCase();
const stop = new Set(['the','and','for','with','that','this','your','you','are','how','what','best','from','their']);
const freq = {};
for (const w of text.match(/[a-z]{4,}/g) || []) {
  if (stop.has(w)) continue;
  freq[w] = (freq[w] || 0) + 1;
}
const commonSubtopics = Object.entries(freq)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 12)
  .map(([w]) => w);

// Target word count: lean on top competitor length signals, default 1500.
const lengths = organic.map((r) => Number(r.word_count || 0)).filter(Boolean);
const avgLen = lengths.length ? lengths.reduce((a, b) => a + b, 0) / lengths.length : 0;
const targetWordCount = Math.min(2600, Math.max(1200, Math.round((avgLen || 1500) / 100) * 100 || 1500));

const serpEmpty = organic.length === 0;

return [
  {
    json: {
      ...topic,
      brief: {
        competitor_headings: competitorHeadings.slice(0, 25),
        paa_questions: paaQuestions,
        common_subtopics: commonSubtopics,
        target_word_count: targetWordCount,
        serp_empty: serpEmpty
      }
    }
  }
];

