// Parse the LLM outline and validate it. Loop back to regenerate ONCE if invalid.
const item = $('Build Research Brief').first().json;
const attempt = Number(item.outline_attempt || 0);

let outline = {};
try {
  const raw = $input.first().json;
  const content = raw.choices?.[0]?.message?.content || '{}';
  outline = JSON.parse(content);
} catch (e) {
  outline = {};
}

const issues = [];
const meta = (outline.meta_description || '').trim();
if (!outline.title) issues.push('missing title');
if (!outline.slug) issues.push('missing slug');
if (!outline.target_keyword) outline.target_keyword = item.target_keyword;
if (meta.length < 120 || meta.length > 158) issues.push(`meta length ${meta.length} not in 120-158`);
const h2 = Array.isArray(outline.h2_sections) ? outline.h2_sections : [];
if (h2.length < 4) issues.push(`only ${h2.length} H2 sections (need 4+)`);

const valid = issues.length === 0;

return [
  {
    json: {
      ...item,
      outline,
      outline_valid: valid,
      outline_issues: issues,
      outline_attempt: attempt + 1,
      can_retry_outline: !valid && attempt < 1
    }
  }
];

