// Compute SEO quality metrics on the finished draft and produce pass/fail + score.
const item = $('Validate Outline').first().json;
let draft = {};
try {
  const content = $input.first().json.choices?.[0]?.message?.content || '{}';
  draft = JSON.parse(content);
} catch (e) {
  draft = {};
}

const html = draft.html_body || '';
const text = html.replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim();
const words = text ? text.split(' ') : [];
const wordCount = words.length;

const keyword = (item.target_keyword || '').toLowerCase();
const kwTokens = keyword.split(/\s+/).filter(Boolean).length || 1;
let kwHits = 0;
if (keyword) {
  const re = new RegExp(keyword.replace(/[.*+?^${}()|[\]\\]/g, '\\$&'), 'gi');
  kwHits = (text.match(re) || []).length;
}
const density = wordCount ? (kwHits * kwTokens / wordCount) * 100 : 0;

const meta = (item.outline?.meta_description || '').trim();
const hasH2 = /<h2[ >]/i.test(html);
const hasH3 = /<h3[ >]/i.test(html);
const internalLinks = (html.match(/<a [^>]*href/gi) || []).length;

// Readability proxy: average sentence length.
const sentences = text.split(/[.!?]+\s/).filter((s) => s.trim().length > 0);
const avgSentence = sentences.length ? wordCount / sentences.length : wordCount;

const keywordInTitle = (item.outline?.title || '').toLowerCase().includes(keyword);
const firstPara = (html.match(/<p[^>]*>(.*?)<\/p>/i)?.[1] || '').toLowerCase();
const keywordInIntro = firstPara.includes(keyword);

const target = item.brief?.target_word_count || 1500;
const issues = [];
let score = 100;
let critical = false;

if (wordCount < target * 0.7) { issues.push(`word count ${wordCount} below target ${target}`); score -= 20; }
if (density < 0.5) { issues.push(`keyword density ${density.toFixed(2)}% too low`); score -= 15; }
if (density > 2.5) { issues.push(`keyword density ${density.toFixed(2)}% (stuffing)`); score -= 20; critical = true; }
if (meta.length < 120 || meta.length > 158) { issues.push(`meta length ${meta.length} out of range`); score -= 10; }
if (!hasH2) { issues.push('no H2 headings'); score -= 15; critical = true; }
if (!hasH3) { issues.push('no H3 headings'); score -= 5; }
if (internalLinks < 1) { issues.push('no internal links'); score -= 10; }
if (avgSentence > 25) { issues.push(`avg sentence ${avgSentence.toFixed(1)} words (hard to read)`); score -= 5; }
if (!keywordInTitle) { issues.push('keyword missing from title'); score -= 10; }
if (!keywordInIntro) { issues.push('keyword missing from intro'); score -= 5; }

score = Math.max(0, score);
const pass = score >= 80 && !critical;

return [
  {
    json: {
      ...item,
      draft_html: html,
      seo: {
        word_count: wordCount,
        keyword_density_pct: Number(density.toFixed(2)),
        meta_length: meta.length,
        has_h2: hasH2,
        has_h3: hasH3,
        internal_links: internalLinks,
        avg_sentence_words: Number(avgSentence.toFixed(1)),
        keyword_in_title: keywordInTitle,
        keyword_in_intro: keywordInIntro
      },
      seo_score: score,
      seo_issues: issues,
      seo_pass: pass
    }
  }
];

