// Assemble a single run report row regardless of pass/fail outcome.
const seoItem = $('SEO Quality Checks').first().json;
return [
  {
    json: {
      run_id: `seo-${Date.now()}`,
      run_started_at: seoItem.run_started_at,
      run_finished_at: new Date().toISOString(),
      queue_id: seoItem.queue_id,
      target_keyword: seoItem.target_keyword,
      seo_score: seoItem.seo_score,
      seo_pass: seoItem.seo_pass,
      outcome: seoItem.seo_pass ? 'drafted' : 'needs_review',
      issues: (seoItem.seo_issues || []).join('; '),
      word_count: seoItem.seo?.word_count || 0,
      keyword_density_pct: seoItem.seo?.keyword_density_pct || 0
    }
  }
];

// On give-up, force a fail outcome so the downstream Slack flag + queue update
// still run with the outline issues attached.
const item = $('Validate Outline').first().json;
return [
  {
    json: {
      ...item,
      draft_html: '',
      seo: { word_count: 0, keyword_density_pct: 0, meta_length: item.outline?.meta_description?.length || 0, has_h2: false, has_h3: false, internal_links: 0, avg_sentence_words: 0, keyword_in_title: false, keyword_in_intro: false },
      seo_score: 0,
      seo_issues: ['outline failed validation twice', ...(item.outline_issues || [])],
      seo_pass: false
    }
  }
];
